function mulberry32(seed) {
    return function() {
        let t = (seed += 0x6D2B79F5);
        t = Math.imul(t ^ (t >>> 15), t | 1);
        t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
        return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
    };
}

const random = mulberry32(1310)

class GridCell {
    constructor() {
        this.circles = [];
    }
}

var circle_id = 0;
class CirclePoint {
    constructor(radius, x, y, x_speed, y_speed, cell_size) {
        this.x = x;
        this.y = y;
        this.x_speed = x_speed;
        this.y_speed = y_speed;
        this.radius = radius;
        this.mass = radius * radius;
        this.grid_x = Math.floor(x / cell_size);
        this.grid_y = Math.floor(y / cell_size);
        this.id = circle_id;
        circle_id++;
    }
}

class CircleSimulation {
    constructor(grid_width, grid_height, cell_size) {
        this.gravity = 0.2;
        this.elasticity = 0.5;

        this.x_bound = grid_width * cell_size;
        this.y_bound = grid_height * cell_size;

        this.grid_width = grid_width;
        this.grid_height = grid_height;
        this.cell_size = cell_size;

        this.grid = Array.from({ length: grid_height }, () =>
            Array.from({ length: grid_width }, () => new GridCell())
        );

        this.circles = [];
    }

    buildGrid() {
        for (let row of this.grid)
            for (let cell of row)
                cell.circles.length = 0;

        for (let circle of this.circles) {
            const gx = Math.floor(circle.x / this.cell_size);
            const gy = Math.floor(circle.y / this.cell_size);
            circle.grid_x = gx;
            circle.grid_y = gy;

            if (gx >= 0 && gx < this.grid_width && gy >= 0 && gy < this.grid_height)
                this.grid[gy][gx].circles.push(circle);
        }
    }

    addCircle(radius, x, y, x_speed, y_speed) {
        this.circles.push(new CirclePoint(radius, x, y, x_speed, y_speed, this.cell_size));
    }

    applySpeedAndGravity() {
        this.circles.forEach(circle => {
            circle.x += circle.x_speed;
            circle.y += circle.y_speed;

            circle.y_speed += this.gravity
        });
    }

    enforceBounds() {
        this.circles.forEach(circle => {
            if ((circle.x > this.x_bound - circle.radius) || (circle.x < 0 + circle.radius)) {
                circle.x = Math.min(Math.max(circle.x, 0 + circle.radius), this.x_bound - circle.radius);
                circle.x_speed *= this.elasticity;
                circle.x_speed = -circle.x_speed;
            }
            if (circle.y > this.y_bound - circle.radius || circle.y < 0 + circle.radius) {
                circle.y = Math.min(Math.max(circle.y, 0 + circle.radius), this.y_bound - circle.radius);
                circle.y_speed *= this.elasticity;
                circle.y_speed = -circle.y_speed;
            }
        });        
    }

    physicsStep() {
        for (let i = 0; i < this.circles.length; i++) {
            const circle = this.circles[i];

            for (let dy = -1; dy <= 1; dy++) {
                for (let dx = -1; dx <= 1; dx++) {
                    const nx = circle.grid_x + dx;
                    const ny = circle.grid_y + dy;

                    if (nx < 0 || nx >= this.grid_width || ny < 0 || ny >= this.grid_height)
                        continue;

                    for (const other of this.grid[ny][nx].circles) {
                        if (other === circle || other.id <= circle.id) continue;

                        const x_dist = circle.x - other.x;
                        const y_dist = circle.y - other.y;

                        const square_distance = x_dist * x_dist + y_dist * y_dist

                        if (square_distance === 0) continue;

                        const min_distance = circle.radius + other.radius;
                        if (square_distance < min_distance * min_distance) {
                            const distance = Math.sqrt(square_distance);
                            const mass1 = circle.mass;
                            const mass2 = other.mass;
                            const total_mass = mass1 + mass2;

                            const x_norm = x_dist / distance;
                            const y_norm = y_dist / distance;
                            const overlap = (min_distance - distance) * 0.8;

                            circle.x += x_norm * overlap * (mass2 / total_mass);
                            circle.y += y_norm * overlap * (mass2 / total_mass);
                            other.x  -= x_norm * overlap * (mass1 / total_mass);
                            other.y  -= y_norm * overlap * (mass1 / total_mass);

                            const dvx = circle.x_speed - other.x_speed;
                            const dvy = circle.y_speed - other.y_speed;
                            const relVel = dvx * x_norm + dvy * y_norm;
                            const impulse = -(1 + this.elasticity) * relVel / (1 / mass1 + 1 / mass2);

                            circle.x_speed += (impulse * x_norm) / mass1;
                            circle.y_speed += (impulse * y_norm) / mass1;
                            other.x_speed  -= (impulse * x_norm) / mass2;
                            other.y_speed  -= (impulse * y_norm) / mass2;
                        }
                    }
                }
            }
        }
    }
}

