var simulation = new CircleSimulation(8, 12, 50);

function draw() {
    if (cooldown_timer == 0) {
        cooldown_timer = cooldown;
        if (simulation.circles.length < spawner_max) {
            simulation.addCircle(Math.floor(random() * 10 + 5), spawner_x, spawner_y, random()-0.5, 0);
        }
        // } else {
        //     cooldown = 1000;
        //     const blob = new Blob([JSON.stringify(simulation.circles, null, 2)], { type: 'text/plain' });
        //     const url = URL.createObjectURL(blob);
        //     const link = document.createElement('a');
        //     link.href = url;
        //     link.download = 'myArray.txt';
        //     link.click();
        // }
    } else {
        cooldown_timer--;
    }

    spawner_x += spawner_dir;

    if (spawner_x >= 370) {
        spawner_dir = -15;
    } else if (spawner_x <= 30) {
        spawner_dir = 15;
    }

    simulation.applySpeedAndGravity();

    simulation.buildGrid();

    for (let samples = 0; samples < 20; samples++) {
        simulation.physicsStep();
        simulation.enforceBounds();
    }

    background(48, 54, 51);
    strokeWeight(4)

    for (let i = 0; i < simulation.circles.length; i++) {
        let circle = simulation.circles[i];

        let r = circle_colors[i][0];
        let g = circle_colors[i][1];
        let b = circle_colors[i][2];

        // let r = 0;
        // let g = 255;
        // let b = 0;

        this.fill(r, g, b);
        this.strokeWeight(0);
        this.circle(circle.x, circle.y, circle.radius * 2);
    }
}